class MyCalendarThree {
public:
    std::map<int, int> events;
    int maxK;

    MyCalendarThree() {
        maxK = 0;
    }

    int book(int startTime, int endTime) {
        events[startTime]++;
        events[endTime]--;
        int k = 0;
        int currentK = 0;
        for (auto& event : events) {
            currentK += event.second;
            maxK = std::max(maxK, currentK);
        }
        return maxK;
    }
};
